1	const neighborPositions = (x: number, y: number): [number, number][] => {
2	  const positions: [number, number][] = [];
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      positions.push([x + dx, y + dy]);
7	    }
8	  }
9	  return positions;
10	};
11	
12	export function nextGeneration(cells: [number, number][]): [number, number][] {
13	  const liveSet = new Set(cells.map(([x, y]) => `${x},${y}`));
14	
15	  const liveNeighborCount = (x: number, y: number): number =>
16	    neighborPositions(x, y).filter(([nx, ny]) => liveSet.has(`${nx},${ny}`)).length;
17	
18	  const survivors = cells.filter(([x, y]) => {
19	    const n = liveNeighborCount(x, y);
20	    return n === 2 || n === 3;
21	  });
22	
23	  const deadNeighborCandidates = new Set<string>();
24	  for (const [x, y] of cells) {
25	    for (const [nx, ny] of neighborPositions(x, y)) {
26	      const key = `${nx},${ny}`;
27	      if (!liveSet.has(key)) deadNeighborCandidates.add(key);
28	    }
29	  }
30	
31	  const born: [number, number][] = [];
32	  for (const key of deadNeighborCandidates) {
33	    const [x, y] = key.split(",").map(Number) as [number, number];
34	    if (liveNeighborCount(x, y) === 3) born.push([x, y]);
35	  }
36	
37	  born.sort(([ax, ay], [bx, by]) => ax !== bx ? ax - bx : ay - by);
38	
39	  return [...survivors, ...born];
40	}
