1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid when single cell dies from underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid when two cells die from underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should bring a dead cell to life when it has exactly 3 live neighbors", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
18	    // Center cell (1,0) has exactly 2 neighbors: (0,0) and (2,0) - it survives
19	    // Outer cells (0,0) and (2,0) each have 1 neighbor - they die
20	    // Dead cell (1,1) has 3 live neighbors - it is born
21	    // Dead cell (1,-1) has 3 live neighbors - it is born
22	    expect(nextGeneration([[0, 0], [1, 0], [2, 0]])).toEqual([[1, 0], [1, -1], [1, 1]]);
23	  });
24	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
25	    // Live cell at (1,1) has exactly 3 live neighbors: (0,0), (1,0), (2,0) - it survives
26	    // All 4 live cells survive (each has 2 or 3 neighbors)
27	    // Dead cells (0,1), (1,-1), (2,1) each have 3 live neighbors - they are born
28	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toEqual([[0, 0], [1, 0], [2, 0], [1, 1], [0, 1], [1, -1], [2, 1]]);
29	  });
30	  it("should kill a live cell when it has more than 3 live neighbors", () => {
31	    // Center cell (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,1) - dies from overpopulation
32	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]])).not.toContainEqual([1, 1]);
33	  });
34	  it("should keep a 2x2 block stable as a still life", () => {
35	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
36	  });
37	  it("should transform a vertical blinker to a horizontal blinker", () => {
38	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toEqual([[-1, 1], [0, 1], [1, 1]]);
39	  });
40	});
